import React, { useContext,useEffect } from 'react';
import {DataContext} from '../contexts/DataContext';

function Header() {
    const { contextData } = useContext(DataContext);
  useEffect(() => {  


  /**
   * Navbar links active state on scroll
   */
  let navbarlinks = document.querySelectorAll('#navbar .scrollto')
  const navbarlinksActive = () => {
    let position = window.scrollY + 200
    navbarlinks.forEach(navbarlink => {
      if (!navbarlink.hash) return
      let section = document.querySelector(navbarlink.hash)
      if (!section) return
      if (position >= section.offsetTop && position <= (section.offsetTop + section.offsetHeight)) {
        navbarlink.classList.add('active')
      } else {
        navbarlink.classList.remove('active')
      }
    })
  }
  window.addEventListener('load', navbarlinksActive) 
  document.addEventListener('scroll', navbarlinksActive)


   }, []);
  return (
    <>
   {/* ======= Header ======= */}
   <header id="header" className="d-flex flex-column justify-content-center">
      
      <nav id="navbar" className="navbar nav-menu">
        <ul>
          <li><a href="#hero" className="nav-link scrollto active"><i className="bx bx-home"></i> <span>{contextData.hero.title}</span></a></li>
          <li><a href="#about" className="nav-link scrollto"><i className="bx bx-user"></i> <span>{contextData.about.title}</span></a></li>
          <li><a href="#resume" className="nav-link scrollto"><i className="bx bx-book"></i> <span>{contextData.resume.title}</span></a></li>
          <li><a href="#skills" className="nav-link scrollto"><i className="bx bx-book-content"></i> <span>{contextData.skills.title}</span></a></li>
          <li><a href="#repos" className="nav-link scrollto"><i className="bx bxl-github"></i> <span>{contextData.repos.title}</span></a></li>
          {/* <li><a href="#services" className="nav-link scrollto"><i className="bx bx-server"></i> <span>Services</span></a></li> */}
          <li><a href="#contact" className="nav-link scrollto"><i className="bx bx-envelope"></i> <span>{contextData.contact.title}</span></a></li>
        </ul>
      </nav>{/* .nav-menu */}
  
    </header>{/* End Header */}
    </>)
      }

export default Header;