import React, { useState, useEffect ,useContext} from 'react';

import Body from './components/Body'
import {DataContext} from './contexts/DataContext'
 
import {common} from '@ioutil/react'; // Import the DemoButton component

const { network: { httpRequest } } = common;
 
if(process.env.REACT_APP_VERBOSE)console.log(process.env.REACT_APP_API_URL)
const App = () => {
   
  
  const { contextData, setContextData } = useContext(DataContext);  
  useEffect(() => { 
    var sp =  window.location.search.split('&');
    var key = sp[0];
    var flags = sp.slice(1);
   
     httpRequest(process.env.REACT_APP_API_URL+'/portfolio/data', { key: key,flags:flags})
    .then(response => {
        if(process.env.REACT_APP_VERBOSE)console.log(response);
       
        setContextData({ ...response,...{key:key,flags:flags}}); 
      
    })
    .catch(err => {
      if(process.env.REACT_APP_VERBOSE)console.error(err);
      setContextData({'error':1,'exception':JSON.stringify(err)});
   
    });
   
  
  }, []);  
  
  return (
  
    <div>  
      {contextData && contextData.error && <div> {contextData.code}: {contextData.exception}</div>  }
      {contextData && !contextData.error && <Body data={contextData}/>}
      {!contextData &&  <div id="preloader"></div> }
  
     </div>
  );
};

export default App;
 